// $json["output"] contém todos os arquivos separados por \n
const lines = $input.first().json.stdout.split("\n");

// Retorna um array de itens, cada item com um caminho
return lines.map(line => ({ json: { path: line } }));

// Pega o HTML
const html = $input.first().json.data;

// Extrai todos os valores percentuais da coluna "with-number"
const matches = [...html.matchAll(/<td class="with-number">([\d.,]+) %<\/td>/g)]
  .map(m => parseFloat(m[1].replace(',', '.')));

// Normalmente os dois últimos valores são "Forms %" e "Lines %" totais
const formsPercent = matches[matches.length - 2];  // Forms %
const linesPercent = matches[matches.length - 1];  // Lines %

// Retorna para o n8n como campos separados
return { formsPercent, linesPercent };

return [
  {
    json: {
      files: $input.all().map(item => {
        const content = Buffer.from(item.binary.data.data, 'base64').toString('utf8');
        // Extrai o namespace usando regex
        const nsMatch = content.match(/\(ns\s+([^\s\)]+)/);
        const ns = nsMatch ? nsMatch[1] : "";
        return {
          name: item.json.fileName,
          content: content,
          path: ns
        };
      })
    }
  }
];

