const lines = $input.first().json.stdout.split("\n");

// Retorna um array de itens, cada item com um caminho
return lines.map(line => ({ json: { path: line } }));

const data = $input.first().json.data;

// Garante que é texto
const text = typeof data === "string" ? data : JSON.stringify(data);

// Captura grupos: survivors e total de mutants
const matches = [...text.matchAll(/(\d+)\s+survivors out of\s+(\d+)\s+mutants/g)];

const results = matches.map(m => {
  const survivors = parseInt(m[1], 10);
  const total = parseInt(m[2], 10);
  const killed = total - survivors;
  const percentage = total > 0 ? (killed / total) * 100 : 0;

  return {
    survivors,
    total,
    killed,
    percentage: Number(percentage.toFixed(2)) // duas casas decimais
  };
});

return [
  {
    json: {
      results
    }
  }
];

